#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t A,B; scanf("%" PRId64 " %" PRId64, &A, &B);
        int64_t oddA = (A + 1) / 2;
        int64_t evenA = A / 2;
        int64_t oddB = (B + 1) / 2;
        int64_t evenB = B / 2;
        int64_t ans = oddA * oddB + evenA * evenB;
        printf("%" PRId64 "\n", ans);
    }
    return 0;
}

